head.script:
scwin.onpageload = function() {
    scwin.sDate = $c.date.getServerDateTime("yyyyMMdd");
	scwin.strFromDate = scwin.sDate.substring(0,6);

    scwin.login = $c.data.getMemInfo(); // 로그인 정보를 가져온다.
	scwin.privAdmin = scwin.login.privAdmin;// ADMIN 권한 CHK : 'T' : ADMIN , 'F': ADMIN 아님

    scwin.currentPage = "";
	scwin.closeMm = $c.date.getServerDateTime("YYYYMM").substr(4,2);
	scwin.gSrchGb = "0"; 
	scwin.vAggrDeptYn= "0";

	scwin.vLoginCoCd = $c.gus.cfIsNull(scwin.login.coCd) ? "" : scwin.login.coCd;             // 소속 자회사  
	scwin.vLoginCoClsCd = $c.gus.cfIsNull(scwin.login.coClsCd) ? "" : scwin.login.coClsCd;    //회계_회사구분('CO035' : 0:동부 EXPRESS)
	scwin.vUserHomeClsCd= scwin.login.userHomeClsCd;        // 사용자소속구분코드   
	scwin.isSubCompany = false;

    ds_search.set("acctDeptLvl", 0);

    const codeOptions = [
        { grpCd : "FI010", compID : "lc_srchBookClsCd", opt :{"range" : "1,001"} }, 

    ];
    $c.data.setCommonCode(codeOptions, scwin.setCommonCodeCallBack);
};

scwin.setCommonCodeCallBack = async function () {
    $c.gus.cfDisableKey();

    scwin.f_setCompanyInfo();
    scwin.f_FieldClear();
    scwin.f_GetUnit();

    lc_clntCnt.setSelectedIndex(0);

};

