    for ( i = 0 ; i < dataList.getRowCount(); i++) {
        //상위거래처
        hAmt1 =  parseInt(dataList.getCellData(i, "thisH1Amt")) + parseInt(dataList.getCellData(i, "thisH2Amt")) + parseInt(dataList.getCellData(i, "thisH3Amt"))
                + parseInt(dataList.getCellData(i, "thisH4Amt")) + parseInt(dataList.getCellData(i, "thisH5Amt")) ;

