                       + $c.num.formatNumber(Math.round(parseInt(dataList.getCellData(i, "thisH1Amt")) / lc_unit.getValue()));
                _hAmt1 = parseInt(dataList.getCellData(i, "thisH1Amt")) ;
                _thisHClntSum =  clntAmt;
            } else {
                hClnt1 = "";
            }

            clntAmt = dataList.getCellData(i, "thisH2Amt");
